import React, { useEffect, useState } from 'react';
import { GlobalSwgSelector } from '../../../../assets/icons/global/GlobalSwgSelector';
import s from './ThisDay.module.scss';
import axios from 'axios';
import { ILocation } from '../../../../types/IWeather';


interface Props {
  data: ILocation[]
}

export const ThisDay = (props: Props) => {

  const lol = () => {
  const [city, setCity] = useState<ILocation[]> ([])

  useEffect( () => {
    fetchCity()
  }, [])

  async function fetchCity() {
    try {
      const response = await axios.get<ILocation[]>(`https://api.weatherapi.com/v1/forecast.json?key=98868634f9274e1083375040222704&q=Almaty&days=7`)
      setCity(response.data)
    } catch (e) {
      alert (e)
    }
    
  }
}

  
    return (
  <div className={s.thisday}>
     <div className={s.top_block}>        
    <div className={s.top_block_wrapper}>  <div className={s.this_temp}>25°</div>
       <div className={s.this_day_name}>Сегодня</div></div>
       <GlobalSwgSelector id='sun' />
      </div>
     <div className={s.bottom_block}> 
     <div className={s.this_city}>
       Город: <span>Алматы</span>
     </div>
  </div>
  </div>
  );
};
